Rule.Source:
		
		import sailpoint.object.CertificationGroup;
		import sailpoint.object.Certification;
		import sailpoint.object.Identity;
  
		String appName = "Azure";
		String LOG_NAME = "org.ascn.rule.ASCN-Certification-PreDelegation-ToCertOWner";
		info(LOG_NAME,"Entering "+LOG_NAME);

		Map results = new HashMap();
		
		try {
			//Fetch the certification owner name
			Identity certOwnerObj = context.getObjectByName(Identity.class, "O365 License Certifiers");
			String certOwner = certOwnerObj.getName(); //certification.getOwner().getName();
			String sysOwner = "IDM Team";

			// Get the certifier's identity
			String certifierName = certification.getCertifiers().get(0);
			Identity certifierObj = context.getObjectByName(Identity.class, certifierName);
			String theCertifiee = entity.getIdentity();
			Identity identity = context.getObjectByName(Identity.class, theCertifiee);
			
			//Update Identity attributes
			String MGR_LEVEL_ATTR = "managerLevel"; 
			String LEGAL_HOLD_ATTR = "archiving";
			List MGR_LEVELS= new ArrayList();
			MGR_LEVELS.add("10");
			MGR_LEVELS.add("11");
			MGR_LEVELS.add("12");
			
			String userMgrLevel = identity.getAttribute(MGR_LEVEL_ATTR);
			Object legalHoldObj  = identity.getAttribute(LEGAL_HOLD_ATTR);
			String certifierMgrLevel = certifierObj.getAttribute(MGR_LEVEL_ATTR);
      boolean isinactive = certifierObj.isInactive();
      
      if(isinactive) {
          results.put("recipientName", certOwner);
					results.put("description", "Certification delegated as Manager Is Inactive");
					results.put("comments", "Reassigned to Cert Owner as the original Certifier / Manager is Inactive: Manager Inactive");
					results.put("reassign", true); // Indicates this is a reassignment
      }
			
			if(identity.getManager() == null){
					results.put("recipientName", sysOwner);
					results.put("description", "Certification delegated as Manager Is missing");
					results.put("comments", "Reassigned due to certificate item manager being NULL: Manager is Null");
					results.put("reassign", true); // Indicates this is a reassignment
			}
			
			if(certifierObj!=null @and certifierMgrLevel !=null @and MGR_LEVELS.contains(certifierMgrLevel)) {
				results.put("recipientName", certOwner);
				results.put("description", "Certification delegated due to certifier being manager level 10, 11 or 12");
				results.put("comments", "Reassigned due to Manager Level being 10, 11 or 12: Manager Level");
				results.put("reassign", true); // Indicates this is a reassignment
			}
			if(identity!=null @and userMgrLevel!=null @and MGR_LEVELS.contains(userMgrLevel)) {
				results.put("recipientName", certOwner);
				results.put("description", "Certification delegated due to certificate Item being manager level 10,11, or 12");
				results.put("comments", "Reassigned as the certificate Item manager level is 10, 11 or 12: Identity Manager Level");
				results.put("reassign", true); // Indicates this is a reassignment
			}
	  } catch (Exception e) {
			error(LOG_NAME,"Error in "+e,e);
	  }
	  info(LOG_NAME,"Exiting "+LOG_NAME);
	  return results;
